using namespace adsk::core;
using namespace adsk::fusion;

Ptr ui;

extern "C" XI_EXPORT bool run(const char* context)
{
    Ptr app = Application::get();
    if (!app)
        return false;

    ui = app->userInterface();
    if (!ui)
        return false;

    Ptr docs = app->documents();
    if (!docs)
        return false;

    // Create a document.
    Ptr doc = docs->add(DocumentTypes::FusionDesignDocumentType);
    if (!doc)
        return false;

    Ptr design = app->activeProduct();
    if (!design)
        return false;

    // Get the root component of the active design
    Ptr rootComp = design->rootComponent();
    if (!rootComp)
        return false;

    // Create sketch
    Ptr sketches = rootComp->sketches();
    if (!sketches)
        return false;

    Ptr sketch = sketches->add(rootComp->xYConstructionPlane());
    if (!sketch)
        return false;

    Ptr curves = sketch->sketchCurves();
    if (!curves)
        return false;

    // Draw some circles.
    Ptr circles = curves->sketchCircles();
    if (!circles)
        return false;

    Ptr circle1 = circles->addByCenterRadius(Point3D::create(0, 0, 0), 2);
    if (!circle1)
        return false;

    Ptr circle2 = circles->addByCenterRadius(Point3D::create(8, 3, 0), 3);
    if (!circle2)
        return false;

    // Add a circle at the center of one of the existing circles.
    Ptr circle3 = circles->addByCenterRadius(circle2->centerSketchPoint(), 4);
    if (!circle3)
        return false;

    return true;
}
